MERGE loyalty_otp AS t
USING (SELECT @otp_mobile AS mobile, @otp_email AS email) AS s
ON (t.mobile = s.mobile OR t.email = s.email)
WHEN MATCHED THEN UPDATE SET otp_code = @otp_code, expires_at = @otp_exp, used = 0
WHEN NOT MATCHED THEN INSERT (mobile, email, otp_code, expires_at, used)
VALUES (@otp_mobile, @otp_email, @otp_code, @otp_exp, 0);`;
msg.params = [
    {name:'otp_code',  type:'VarChar(10)',  value: otp_code},
    {name:'otp_exp',   type:'VarChar(30)',  value: otp_exp},
    {name:'otp_mobile',type:'VarChar(20)',  value: otp_mobile},
    {name:'otp_email', type:'VarChar(100)', value: otp_email},
];
return msg;

const b = msg.payload;
const mobile = (b.mobile || '').trim();
const email = (b.email || '').trim();
const otp = (b.otp || '').trim();
if (!mobile && !email) {
    msg.statusCode = 400;
    msg.payload = {ok: false, error: 'mobile or email required'};
    return [null, msg];
}
