msg.query = `SELECT id, mobile, email, otp_code, expires_at, used
FROM loyalty_otp
WHERE (mobile = @mobile OR email = @email) AND used = 0
ORDER BY expires_at DESC;`;
msg.params = [
    {name:'mobile', type:'VarChar(20)', value: mobile},
    {name:'email',  type:'VarChar(100)', value: email},
];
return [msg, null];

const rows = msg.payload;
if (!rows || !rows.length) {
    msg.statusCode = 400;
    msg.payload = {ok: false, error: 'OTP not found or expired'};
    return msg;
}
const r = rows[0];
if (r.used === 1 || r.used === '1' || r.used === true) {
    msg.statusCode = 400;
    msg.payload = {ok: false, error: 'OTP already used'};
    return msg;
}
const now = new Date();
const exp = new Date(r.expires_at);
if (now > exp) {
