if (!Object.keys(updates).length) {
    msg.statusCode = 400;
    msg.payload = {ok: false, error: 'No fields provided'};
    return [null, msg];
}
let expr = 'metadata';
const params = [{name:'id', type:'VarChar(20)', value: id}];
let paramIdx = 0;

for (const [section, val] of Object.entries(updates)) {
    if (typeof val === 'object' && val !== null) {
        for (const [k, v] of Object.entries(val)) {
            const pname = 'p' + paramIdx++;
            const sv = typeof v === 'string' ? v : JSON.stringify(v);
            expr = `JSON_MODIFY(${expr}, '$.${section}.${k}', @${pname})`;
            params.push({name:pname, type:'NVarChar(4000)', value: sv});
        }
    } else {
        const pname = 'p' + paramIdx++;
        expr = `JSON_MODIFY(${expr}, '$.${section}', @${pname})`;
        params.push({name:pname, type:'NVarChar(4000)', value: val});
    }
}

msg.query = `USE UbeLoyalty; UPDATE loyalty_members SET ${expr} WHERE member_id = @id;`;
msg.params = params;
