function ctaDecrypt(sInput) {
    let icNewText = "";
    for (let i = 0; i < sInput.length; i++) {
        let c = sInput.charCodeAt(i);
        if (c >= 192 && c <= 217) c -= 127;
        else if (c >= 218 && c <= 243) c -= 121;
        else if (c >= 244 && c <= 253) c -= 196;
        icNewText += String.fromCharCode(c);
    }
    return icNewText;
}

