/* ════ OTP INPUT HELPERS ════ */
function setupOTPBoxes(selector, submitFn) {
  const boxes = document.querySelectorAll(selector);
  boxes.forEach((box, idx) => {
    box.addEventListener('input', () => {
      if (box.value.length === 1 && idx < boxes.length - 1) boxes[idx + 1].focus();
      const otp = Array.from(boxes).map(b => b.value).join('');
      if (otp.length === boxes.length) submitFn();
    });
    box.addEventListener('keydown', (e) => {
      if (e.key === 'Backspace') {
        if (box.value === '' && idx > 0) { boxes[idx - 1].focus(); boxes[idx - 1].value = ''; }
      }
      if (e.key === 'Enter') {
        const otp = Array.from(boxes).map(b => b.value).join('');
        if (otp.length === boxes.length) submitFn();
      }
    });
    box.addEventListener('focus', () => box.select());
    box.addEventListener('paste', (e) => {
      e.preventDefault();
      const pasted = (e.clipboardData.getData('text') || '').replace(/\D/g, '').slice(0, boxes.length);
      if (pasted.length > 0) {
        pasted.split('').forEach((ch, i) => { if (boxes[i]) boxes[i].value = ch; });
        const lastIdx = Math.min(pasted.length, boxes.length) - 1;
        boxes[lastIdx].focus();
        if (pasted.length === boxes.length) submitFn();
      }
    });
  });
}
function clearOTPBoxes(selector) {
  const boxes = document.querySelectorAll(selector);
  boxes.forEach(b => b.value = '');
  if (boxes.length > 0) boxes[0].focus();
}
function shakeOTPBoxes(selector) {
  const boxes = document.querySelectorAll(selector);
  boxes.forEach(b => {
    b.classList.add('otp-error');
    setTimeout(() => b.classList.remove('otp-error'), 600);
  });
}

