let _verifyingRegOTP = false;

async function verifyOTP() {
  if (_verifyingRegOTP) return;
  const boxes = document.querySelectorAll('.otp-box:not(.login-otp-box)');
  const otp = Array.from(boxes).map(b => b.value).join('');
  if (otp.length < 6) return;
  _verifyingRegOTP = true;
  const dest = currentMethod === 'mobile'
    ? document.getElementById('inp-mobile').value.trim()
    : document.getElementById('inp-email').value.trim();
  try {
    /* ── Step 1: Verify OTP ── */
    const vRes = await fetch(`${API}/loyalty/otp/verify`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ [currentMethod]: dest, otp })
    });
    const vData = await vRes.json();
    if (!vData.ok) {
      shakeOTPBoxes('.otp-box:not(.login-otp-box)');
      setTimeout(() => clearOTPBoxes('.otp-box:not(.login-otp-box)'), 500);
      _verifyingRegOTP = false;
      return;
    }

    /* ── Step 2: Try to register ── */
    const rRes = await fetch(`${API}/loyalty/register`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        first_name: document.getElementById('fn').value.trim(),
        last_name: document.getElementById('ln').value.trim(),
        [currentMethod]: dest,
        birthday: document.getElementById('bday').value || null
      })
    });
    const rData = await rRes.json();

    if (rData.ok && rData.member_id) {
      /* ── New member — load and go ── */
      await loadMember(rData.member_id);
    } else {
      /* ── Already exists (409) — just log them in ── */
      const lRes = await fetch(`${API}/loyalty/member/${encodeURIComponent(dest)}`);
      const lData = await lRes.json();
      if (lData.ok && lData.member && lData.member.member_id) {
        setMember(lData.member);
        saveSession(lData.member.member_id);
      } else {
        alert('Could not load your account. Please try signing in.');
        _verifyingRegOTP = false;
        show('s-login');
        return;
      }
    }

    if (!member || !member.member_id) {
      alert('Could not load your account. Please try signing in.');
      _verifyingRegOTP = false;
      show('s-login');
      return;
    }

    window.registerPush(member.member_id);
    await refreshMemberData(true);
    _verifyingRegOTP = false;
    showWallet();

  } catch (e) {
    console.error('Registration error:', e);
    alert('Something went wrong. Please try again.');
    _verifyingRegOTP = false;
    show('s-register');
  }
}

