/* ════ SHEET SWIPE ════ */
function initSheetDrag(handleId, sheetId, closeFn) {
  const handle = document.getElementById(handleId);
  const sheet  = document.getElementById(sheetId);
  if (!handle || !sheet) return;
  let startY = 0, currentY = 0, dragging = false;
  const CLOSE_THRESHOLD = 80;
  function onStart(y) { startY = y; currentY = 0; dragging = true; sheet.style.transition = 'none'; }
  function onMove(y)  { if (!dragging) return; const delta = Math.max(0, y - startY); currentY = delta; sheet.style.transform = `translateY(${delta}px)`; }
  function onEnd()    {
    if (!dragging) return;
    dragging = false;
    sheet.style.transition = 'transform .25s ease';
    if (currentY > CLOSE_THRESHOLD) {
      sheet.style.transform = 'translateY(100%)';
      setTimeout(() => { sheet.style.transform = ''; sheet.style.transition = ''; closeFn(); }, 250);
    } else { sheet.style.transform = ''; }
  }
  handle.addEventListener('touchstart', e => onStart(e.touches[0].clientY), { passive: true });
  handle.addEventListener('touchmove',  e => onMove(e.touches[0].clientY),  { passive: true });
  handle.addEventListener('touchend',   onEnd);
  handle.addEventListener('mousedown', e => { onStart(e.clientY); });
  window.addEventListener('mousemove', e => { if (dragging) onMove(e.clientY); });
  window.addEventListener('mouseup',   onEnd);
}

