/* ════ INIT ════ */
async function init() {
  registerServiceWorker();
  if (isInstalledPWA()) hideInstallButton();
  const savedId = getSavedSession();
  if (savedId) {
    try {
      const res = await fetch(`${API}/loyalty/member/${encodeURIComponent(savedId)}`);
      const data = await res.json();
      if (data.ok && data.member && data.member.member_id) {
        setMember(data.member);
        window.registerPush(data.member.member_id);
        await refreshMemberData(true);
        hideSplash();
        showWallet();
        return;
      }
    } catch (e) {
      console.warn('Session restore failed:', e);
    }
    clearSession();
  }
  hideSplash();
  show('s-register');
}

