// ── Push notification registration (settings page) ──
async function registerDevicePush() {
  const btn = document.getElementById('set-push-btn');
  const status = document.getElementById('set-push-status');
  if (!btn || !status) return;
  btn.disabled = true;
  status.textContent = 'Registering...';

  if (typeof window.registerPush === 'function') {
    try {
      await window.registerPush(member.member_id);
      status.textContent = 'Device registered!';
      loadRegisteredDevices();
    } catch(e) {
      status.textContent = 'Error: ' + e.message;
    }
    btn.disabled = false;
    return;
  }

  try {
    if (!('Notification' in window)) {
      status.textContent = 'Notifications not supported.';
      btn.disabled = false;
      return;
    }
    const perm = await Notification.requestPermission();
    if (perm !== 'granted') {
      status.textContent = 'Permission denied.';
      btn.disabled = false;
      return;
    }
    const mod = await import('/firebase-push.js');
    if (typeof window.registerPush === 'function') {
      await window.registerPush(member.member_id);
      status.textContent = 'Device registered!';
      loadRegisteredDevices();
    } else {
      status.textContent = 'Firebase load error.';
    }
  } catch(e) {
    status.textContent = 'Error: ' + e.message;
  }
  btn.disabled = false;
}

function escHtml(str) {
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

// Device token storage for unregister
var _deviceTokens = [];

async function loadRegisteredDevices() {
  if (!member || !member.member_id) { console.warn('loadRegisteredDevices: no member'); return; }
  const container = document.getElementById('device-items');
  if (!container) return;
  try {
    const res = await fetch('/api/devices/' + encodeURIComponent(member.member_id));
    const data = await res.json();
    if (data.ok && data.devices && data.devices.length > 0) {
      container.innerHTML = data.devices.map(function(d, i) {
        var hint = d.device_hint || 'Unknown';
        var lastSeen = d.last_seen_at ? new Date(d.last_seen_at).toLocaleString() : '';
        var created = d.created_at ? new Date(d.created_at).toLocaleDateString() : '';
        var status = lastSeen ? 'Last seen: ' + lastSeen : 'Registered: ' + created;
        return '<div class="device-row" style="padding:6px 0;display:flex;align-items:center;gap:6px;">' +
          '<span style="font-size:14px;">📱</span>' +
          '<div style="flex:1;min-width:0;">' +
            '<div style="font-size:12px;font-weight:600;">' + escHtml(hint) + '</div>' +
            '<div style="font-size:10px;color:var(--ink3);margin-top:2px;">' + status + '</div>' +
          '</div>' +
          '<button onclick="unreg(this,' + i + ')" style="font-size:10px;padding:4px 8px;border-radius:6px;border:1px solid #C0392B;background:#FDECEA;color:#C0392B;cursor:pointer;font-weight:600;white-space:nowrap;">Remove</button>' +
        '</div>';
      }).join('');
      // Store tokens for unregister
      window._devToks = data.devices.map(function(d) { return d.token || ''; });
    } else {
      container.innerHTML = '<div style="color:var(--ink3);font-size:12px;">No devices registered.</div>';
    }
  } catch(e) {
    container.innerHTML = '<div style="color:var(--red);font-size:12px;">Could not load devices.</div>';
    console.error('Device list error:', e.message);
  }
}

function unreg(btn, idx) {
  console.log('unreg called, idx=' + idx);
  if (!member || !member.member_id) { console.warn('no member'); return; }
  var toks = window._devToks || [];
  var token = toks[idx];
  console.log('token=' + (token ? token.substring(0,20) + '...' : 'empty'));
  if (!token) { console.warn('no token'); return; }
  if (!confirm('Remove this device?')) { console.log('cancelled'); return; }
  console.log('confirmed, sending request');
  btn.disabled = true;
  btn.textContent = '...';
  var xhr = new XMLHttpRequest();
  xhr.open('POST', '/loyalty/device/unregister', true);
  xhr.setRequestHeader('Content-Type', 'application/json');
  xhr.onload = function() {
    console.log('response status=' + xhr.status);
    try {
      var data = JSON.parse(xhr.responseText);
      console.log('response data=', JSON.stringify(data));
      if (data && data.ok) {
        console.log('success, reloading devices');
        loadRegisteredDevices();
      } else {
        alert('Failed: ' + (data && data.error ? data.error : 'unknown'));
        btn.disabled = false;
        btn.textContent = 'Remove';
      }
    } catch(e) {
      alert('Parse error: ' + e.message);
      btn.disabled = false;
      btn.textContent = 'Remove';
    }
  };
  xhr.onerror = function() {
    alert('Network error');
    btn.disabled = false;
    btn.textContent = 'Remove';
  };
  xhr.send(JSON.stringify({ member_id: member.member_id, token: token }));
}function closePrivacy() { document.getElementById('privacy-sheet-bg').classList.remove('open'); }
function handlePrivacyBackdrop(e) { if (e.target === document.getElementById('privacy-sheet-bg')) closePrivacy(); }

