const CACHE_NAME = 'ubecard-v1';
const PRECACHE_URLS = [
  '/',
  'app.js',
  'app.css',
  'manifest.json',
  'https://fonts.googleapis.com/css2?family=Noto+Serif:ital,wght@0,700;1,400&family=Noto+Sans:wght@300;400;500;600;700&display=swap',
  'https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js',
  'https://raw.githubusercontent.com/roycegerikchua/ebtapp/refs/heads/main/ebt.png'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => cache.addAll(PRECACHE_URLS))
      .then(() => self.skipWaiting())
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then(keys =>
      Promise.all(
        keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k))
      )
    ).then(() => self.clients.claim())
  );
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Skip API calls — always go to network
  if (url.hostname === 'loyalty.engbeetin.com') return;

  event.respondWith(
    caches.match(event.request).then(cached => {
      // Network-first for HTML, cache-first for assets
      if (event.request.mode === 'navigate') {
        return fetch(event.request)
          .then(response => {
            const clone = response.clone();
            caches.open(CACHE_NAME).then(c => c.put(event.request, clone));
            return response;
          })
          .catch(() => cached);
      }
      return cached || fetch(event.request).then(response => {
        const clone = response.clone();
        caches.open(CACHE_NAME).then(c => c.put(event.request, clone));
        return response;
      });
    })
  );
});

