async function registerPush(memberId) {
  if (!memberId) return;
  if (!('Notification' in window)) return;
  if (!('serviceWorker' in navigator)) return;

  try {
    const swReg = await navigator.serviceWorker.register('/firebase-messaging-sw.js');

    const permission = await Notification.requestPermission();
    if (permission !== 'granted') {
      console.log('[Push] Permission not granted');
      return;
    }

    const token = await getToken(messaging, {
      vapidKey: VAPID_KEY,
      serviceWorkerRegistration: swReg
    });

    if (!token) {
      console.warn('[Push] No token — check VAPID key');
      return;
    }

    const ua = navigator.userAgent;
    let browser = 'Unknown', os = 'Unknown';
    if (/Chrome\//.test(ua) && !/Edg\//.test(ua)) browser = 'Chrome';
    else if (/Firefox\//.test(ua)) browser = 'Firefox';
    else if (/Edg\//.test(ua)) browser = 'Edge';
    else if (/Safari\//.test(ua)) browser = 'Safari';
    if (/iPhone|iPad/.test(ua)) os = 'iOS';
    else if (/Android/.test(ua)) os = 'Android';
    else if (/Windows/.test(ua)) os = 'Windows';
    else if (/Mac OS X/.test(ua)) os = 'macOS';
    else if (/Linux/.test(ua)) os = 'Linux';

    await fetch(API + '/loyalty/device/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        member_id:   memberId,
        fcm_token:   token,
        device_hint: browser + '/' + os
      })
    });

    localStorage.setItem('ube_fcm_token',     token);
    localStorage.setItem('ube_fcm_member_id', memberId);
    console.log('[Push] Registered: ' + browser + '/' + os);

    onMessage(messaging, function(payload) {
      var title = (payload.notification && payload.notification.title) || 'Ube Card';
      var body  = (payload.notification && payload.notification.body)  || '';

      showInAppBanner(title, body);

      if (typeof window.refreshMemberData === 'function') {
        window.refreshMemberData(true);
      }

      if ('serviceWorker' in navigator && navigator.serviceWorker.controller) {
        navigator.serviceWorker.controller.postMessage({
          type: 'PUSH_RECEIVED',
          refresh: true
        });
      }
    });

  } catch (err) {
    console.warn('[Push] Registration failed:', err);
  }
}

async function unregisterPush(memberId) {
  try {
    var token = localStorage.getItem('ube_fcm_token');
    var mid   = memberId || localStorage.getItem('ube_fcm_member_id');
    if (token && mid) {
