async function refreshMemberData(force) {
  if (!member || !member.member_id) return;
  const now = Date.now();
  if (!force && _refreshingMemberData) return;
  if (!force && now - _lastRefreshAt < 1500) return;
  _refreshingMemberData = true;
  _lastRefreshAt = now;
  try {
    await loadMember(member.member_id);
    renderTxns(member?.recent_txns || [], 'home-txn-list', 4);
    renderNearestReward();
    const historyScreen = document.getElementById('s-history');
    if (historyScreen && historyScreen.classList.contains('active')) {
      await loadHistory();
    }
  } catch (e) {
    console.warn('refreshMemberData failed:', e);
  } finally {
    _refreshingMemberData = false;
  }
}

function setupAutoRefreshHooks() {
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible') refreshMemberData(true);
  });
  window.addEventListener('focus', () => refreshMemberData(true));
  window.addEventListener('pageshow', () => refreshMemberData(true));
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.addEventListener('message', (event) => {
      const data = event.data || {};
      if (data.type === 'LOYALTY_REFRESH' || data.type === 'PUSH_RECEIVED' ||
          data.type === 'NOTIFICATION_CLICKED' || data.refresh === true) {
        refreshMemberData(true);
      }
    });
  }
}

