      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ [loginMethod]: dest })
    });
  } catch (e) {}
  if (!resend) {
    show('s-login-otp');
    clearOTPBoxes('.login-otp-box');
    setTimeout(() => document.querySelector('.login-otp-box').focus(), 350);
  }
}

let _verifyingLoginOTP = false;
async function verifyLoginOTP() {
  if (_verifyingLoginOTP) return;
  const boxes = document.querySelectorAll('.login-otp-box');
  const otp = Array.from(boxes).map(b => b.value).join('');
  if (otp.length < 6) return;
  _verifyingLoginOTP = true;
  const dest = loginMethod === 'mobile'
    ? document.getElementById('login-mobile').value.trim()
    : document.getElementById('login-email').value.trim();
  try {
    /* ── Step 1: Verify OTP ── */
    const vRes = await fetch(`${API}/loyalty/otp/verify`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ [loginMethod]: dest, otp })
    });
    const vData = await vRes.json();
    if (!vData.ok) {
      shakeOTPBoxes('.login-otp-box');
      setTimeout(() => clearOTPBoxes('.login-otp-box'), 500);
      _verifyingLoginOTP = false;
      return;
    }

    /* ── Step 2: Fetch member by mobile/email ── */
    const res = await fetch(`${API}/loyalty/member/${encodeURIComponent(dest)}`);
    const data = await res.json();
    if (data.ok && data.member && data.member.member_id) {
      setMember(data.member);
      saveSession(data.member.member_id);
      window.registerPush(data.member.member_id);
      await refreshMemberData(true);
      _verifyingLoginOTP = false;
      showWallet();
    } else {
      alert('No Ube Card found for this ' + loginMethod + '. Please register first.');
      _verifyingLoginOTP = false;
      show('s-register');
    }
  } catch (e) {
    console.error('Login error:', e);
    alert('Something went wrong. Please try again.');
    _verifyingLoginOTP = false;
    show('s-login');
  }
}

