/* ════ TIER SKIN ════ */
function applyTierSkin(tier) {
  const tierMap = { 'Silver': 'tier-member', 'Gold': 'tier-gold', 'Platinum': 'tier-platinum' };
  const cls = tierMap[tier] || 'tier-member';
  const allTiers = ['tier-member', 'tier-gold', 'tier-platinum'];
  const card = document.querySelector('.ube-card');
  if (card) { card.classList.remove(...allTiers); card.classList.add(cls); }
  const qrCard = document.querySelector('.qr-card');
  if (qrCard) { qrCard.classList.remove(...allTiers); qrCard.classList.add(cls); }
  const qrContainer = document.getElementById('qr-canvas');
  if (qrContainer) qrContainer._tierQrColor = tier === 'Platinum' ? '#1A2235' : '#3D0C3E';
}

function setMember(m) {
  member = m;
  const fullName = `${m.first_name} ${m.last_name}`;
  const pts = m.points || 0;
  const lifetime = m.lifetime_points || 0;

  document.getElementById('w-name').textContent = fullName + ' ✦';
  document.getElementById('w-tier-badge').textContent = `⬡ ${m.tier}`;
  document.getElementById('w-pts').textContent = pts.toLocaleString();
  document.getElementById('w-equiv').textContent = `₱${pts.toLocaleString()}`;
  document.getElementById('w-member-name').textContent = fullName;
  document.getElementById('w-card-id').textContent = m.member_id;

  const tiers = { Silver: { next: 'Gold', threshold: 2000 }, Gold: { next: 'Platinum', threshold: 5000 }, Platinum: { next: 'Platinum', threshold: 5000 } };
  const t = tiers[m.tier] || tiers.Silver;
  const pct = m.tier === 'Platinum' ? 100 : Math.min(100, Math.round(lifetime / t.threshold * 100));
  document.getElementById('tier-progress-label').textContent = m.tier === 'Platinum' ? 'Platinum member' : 'Progress to ' + t.next;
  document.getElementById('tier-progress-value').textContent = m.tier === 'Platinum' ? 'Max tier!' : `${Math.max(0, t.threshold - lifetime).toLocaleString()} pts to go`;
  document.getElementById('tier-fill').style.width = pct + '%';

  const qrContainer = document.getElementById('qr-canvas');
  qrContainer.innerHTML = '';
  const qrDark = m.tier === 'Platinum' ? '#1A2235' : '#3D0C3E';
  new QRCode(qrContainer, {
    text: m.member_id, width: 174, height: 174,
    colorDark: qrDark, colorLight: '#FFFFFF',
    correctLevel: QRCode.CorrectLevel.M
  });
  document.getElementById('qr-name').textContent = fullName;
  document.getElementById('qr-id').textContent = m.member_id;
  document.getElementById('qr-badge').textContent = `⬡ ${m.tier} · ${pts.toLocaleString()} pts · ≈ ₱${pts.toLocaleString()}`;

  document.getElementById('p-avatar').textContent = (m.first_name[0] + (m.last_name[0] || '')).toUpperCase();
  document.getElementById('p-name').textContent = fullName;
  const joined = m.joined_at
    ? new Date(m.joined_at).toLocaleDateString('en-PH', { month: 'long', year: 'numeric' }) : '';
  document.getElementById('p-since').textContent = joined ? `Ube Card member since ${joined}` : 'Ube Card member';
  document.getElementById('p-mobile').textContent = m.mobile || '—';
  document.getElementById('p-email').textContent = m.email || '—';
  document.getElementById('p-bday').textContent = (function () {
    if (!m.birthday) return '—';
    const parts = m.birthday.split('-');
    if (parts.length < 3) return '—';
    const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
    return months[parseInt(parts[1], 10) - 1] + ' ' + parseInt(parts[2], 10);
  })();
  document.getElementById('p-card').textContent = m.member_id;
  document.getElementById('p-tier').textContent = `⬡ ${m.tier}`;
  document.getElementById('p-pts').textContent = `${pts.toLocaleString()} pts`;
  document.getElementById('p-lifetime').textContent = `${lifetime.toLocaleString()} pts`;

  renderTxns(m.recent_txns || [], 'home-txn-list', 4);
  applyTierSkin(m.tier);
  renderNearestReward();
}

/* ════ HOME WIDGET: compact txn list (unchanged style) ════ */
function renderTxns(txns, listId, limit) {
  const list = document.getElementById(listId);
  if (!list) return;
  if (!txns || !txns.length) {
    list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--ink3);font-size:13px;">No transactions yet</div>';
    return;
  }
  const icons = { earn: '🛍', redeem: '✨', birthday: '🎂' };
  list.innerHTML = txns.slice(0, limit || txns.length).map(t => {
    const pts = t.points_delta;
    const plus = pts > 0;
    const icon = icons[t.txn_type] || '🛍';
    const cls = t.txn_type === 'birthday' ? 'bday' : t.txn_type;
    const d = new Date(t.txn_at);
    const dateStr = d.toLocaleDateString('en-PH', { month: 'short', day: 'numeric' }) + ' ' +
      d.toLocaleTimeString('en-PH', { hour: '2-digit', minute: '2-digit' });
    const displayName = t.branch_name || (t.branch && t.branch !== t.br_code ? t.branch : null) || t.branch || 'Eng Bee Tin';
    return `<div class="txn-item">
              <div class="txn-icon ${cls}">${icon}</div>
              <div class="txn-info">
                <div class="txn-name">${displayName}</div>
                <div class="txn-date">${dateStr}${t.txn_type === 'earn' ? ' · ₱' + (t.amount_spent || 0).toLocaleString() + ' purchase' : ''}</div>
              </div>
              <div class="txn-pts ${plus ? 'plus' : 'minus'}">${plus ? '+' : ''}${pts}</div>
            </div>`;
  }).join('');
}

/* ════ HISTORY SCREEN: date-grouped, paginated ════ */
const HISTORY_PAGE = 10;
let _historyAllTxns = [];
let _historyShown   = 0;

function historyDateLabel(dateStr) {
  const d     = new Date(dateStr);
  const today = new Date();
  const yest  = new Date(); yest.setDate(yest.getDate() - 1);
  const same  = (a, b) =>
    a.getFullYear() === b.getFullYear() &&
    a.getMonth()    === b.getMonth()    &&
    a.getDate()     === b.getDate();
  if (same(d, today)) return 'Today';
  if (same(d, yest))  return 'Yesterday';
  return d.toLocaleDateString('en-PH', { month: 'short', day: 'numeric' });
}

function renderHistoryRow(t, delay) {
  const isEarn  = t.txn_type === 'earn';
  const isBday  = t.txn_type === 'birthday';
  const pts     = Math.abs(t.points_delta);
  const d       = new Date(t.txn_at);
  const timeStr = d.toLocaleTimeString('en-PH', { hour: 'numeric', minute: '2-digit', hour12: true });
  const branch  = t.branch_name || (t.branch && t.branch !== t.br_code ? t.branch : null) || t.branch || 'Eng Bee Tin';

  const icon    = isBday ? '🎂' : isEarn ? '🧾' : '🎁';
  const iconCls = isBday ? 'bday' : isEarn ? 'earn' : 'redeem';

  const primary = isBday
    ? 'Birthday bonus'
    : isEarn
      ? 'Purchase — ₱' + (t.amount_spent || 0).toLocaleString('en-PH')
      : 'Redeemed points';

  const secondary = `${timeStr} · ${branch}`;

  const ptsLabel = isBday || isEarn ? `+${pts} pts` : `Redeemed ${pts} pts`;
  const ptsCls   = (isEarn || isBday) ? 'earn' : 'redeem';

  const subLine = (isEarn && t.amount_spent)
    ? `<div class="h-txn-sub">₱${(t.amount_spent).toLocaleString('en-PH')} purchase</div>`
    : isBday
      ? `<div class="h-txn-sub bday">🎂 Birthday reward</div>`
      : `<div class="h-txn-sub redeem-sub">−${pts} pts</div>`;

  return `<div class="h-txn-item" style="animation-delay:${delay}s">
    <div class="h-txn-icon ${iconCls}">${icon}</div>
    <div class="h-txn-main">
      <div class="h-txn-primary">${primary}</div>
      <div class="h-txn-secondary">${secondary}</div>
    </div>
    <div class="h-txn-right">
      <div class="h-txn-pts ${ptsCls}">${ptsLabel}</div>
      ${subLine}
    </div>
  </div>`;
}

function renderHistoryGroups(txns) {
  if (!txns || !txns.length)
    return '<div class="h-empty"><div class="h-empty-icon">📋</div>No transactions yet</div>';
  const groups = {};
  txns.forEach(t => {
    const lbl = historyDateLabel(t.txn_at);
    if (!groups[lbl]) groups[lbl] = [];
    groups[lbl].push(t);
  });
  return Object.entries(groups).map(([label, items]) =>
    `<div class="h-group">
      <div class="h-group-label">${label}</div>
      <div class="h-txn-list">${items.map((t, i) => renderHistoryRow(t, i * 0.04)).join('')}</div>
    </div>`
  ).join('');
}

function renderHistorySummary() {
  if (!member) return;
  const pts      = member.points || 0;
  const lifetime = member.lifetime_points || 0;
  const tiers    = { Silver: { next: 'Gold', threshold: 2000 }, Gold: { next: 'Platinum', threshold: 5000 }, Platinum: { next: 'Platinum', threshold: 5000 } };
  const t        = tiers[member.tier] || tiers.Silver;
  const pct      = member.tier === 'Platinum' ? 100 : Math.min(100, Math.round(lifetime / t.threshold * 100));

  const el = id => document.getElementById(id);
  if (el('h-balance'))  el('h-balance').textContent  = pts.toLocaleString('en-PH') + ' pts';
  if (el('h-equiv'))    el('h-equiv').textContent    = '≈ ₱' + pts.toLocaleString('en-PH') + ' redemption value';
  if (el('h-tier-cur')) el('h-tier-cur').textContent = member.tier;
