async function saveSettings() {
  if (!member || !member.member_id) return;

  const btn = document.getElementById('settings-save-btn');
  const msg = document.getElementById('settings-saved-msg');
  btn.classList.add('saving');
  btn.textContent = 'Saving…';
  msg.classList.remove('visible');

  const privacyChecked = document.getElementById('set-data-privacy').checked;
  const oldMeta        = member.metadata || {};
  const oldConsents    = oldMeta.consents || {};

  // Build the consent_date: set it when toggling ON, keep existing if already on
  let consentDate = oldConsents.consent_date || null;
  if (privacyChecked && !oldConsents.data_privacy_signed) {
    consentDate = new Date().toISOString();
  } else if (!privacyChecked) {
    consentDate = null;
  }

  const payload = {
    consents: {
      marketing_sms:       document.getElementById('set-marketing-sms').checked,
      marketing_email:     document.getElementById('set-marketing-email').checked,
      data_privacy_signed: privacyChecked,
      consent_date:        consentDate
    },
    address: {
      street:   document.getElementById('set-addr-street').value.trim(),
      city:     document.getElementById('set-addr-city').value.trim(),
      province: document.getElementById('set-addr-province').value.trim(),
      zip:      document.getElementById('set-addr-zip').value.trim()
    },
    preferences: {
      favorite_branch:   document.getElementById('set-pref-branch').value.trim(),
      preferred_contact: document.getElementById('set-pref-contact').value
    },
    demographics: {
      gender: document.getElementById('set-demo-gender').value
    }
  };

  try {
    const res = await fetch(`${API}/loyalty/member/${encodeURIComponent(member.member_id)}/metadata`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await res.json();
    if (data.ok) {
      // Merge returned metadata back into member object
      member.metadata = data.metadata;
      msg.textContent = '✓ Saved';
      msg.classList.add('visible');
      setTimeout(() => msg.classList.remove('visible'), 2500);
    } else {
      msg.textContent = '✗ ' + (data.error || 'Save failed');
      msg.style.color = '#d44';
      msg.classList.add('visible');
      setTimeout(() => { msg.classList.remove('visible'); msg.style.color = ''; }, 3000);
    }
  } catch (e) {
    console.error('saveSettings error:', e);
    msg.textContent = '✗ Network error';
    msg.style.color = '#d44';
    msg.classList.add('visible');
    setTimeout(() => { msg.classList.remove('visible'); msg.style.color = ''; }, 3000);
  } finally {
    btn.classList.remove('saving');
    btn.textContent = 'Save changes';
  }
}

/* ════ SETTINGS: CONTACT INFO (with OTP verification) ════ */

let _contactOTPField = null;  // 'mobile' or 'email'
let _contactOTPValue = null;  // the value being verified

function populateContactFields() {
  if (!member) return;

  const mobileInput = document.getElementById('set-contact-mobile');
  const emailInput  = document.getElementById('set-contact-email');
  const mobileBadge = document.getElementById('set-mobile-badge');
  const emailBadge  = document.getElementById('set-email-badge');
  const sendBtn     = document.getElementById('set-contact-send-otp-btn');
  const otpSection  = document.getElementById('set-contact-otp-section');

  const hasMobile = !!member.mobile;
  const hasEmail  = !!member.email;

  // Mobile
  mobileInput.value = member.mobile || '';
  if (hasMobile) {
    mobileInput.disabled = true;
    mobileBadge.classList.add('visible');
  } else {
    mobileInput.disabled = false;
    mobileBadge.classList.remove('visible');
  }

  // Email
  emailInput.value = member.email || '';
  if (hasEmail) {
    emailInput.disabled = true;
    emailBadge.classList.add('visible');
  } else {
    emailInput.disabled = false;
    emailBadge.classList.remove('visible');
  }

  // Show send OTP button only if a field is still empty
  if (!hasMobile || !hasEmail) {
    sendBtn.style.display = '';
    sendBtn.textContent = !hasMobile ? 'Verify & add mobile' : 'Verify & add email';
  } else {
    sendBtn.style.display = 'none';
  }

  // Reset OTP section
  otpSection.style.display = 'none';
  _contactOTPField = null;
  _contactOTPValue = null;
  clearOTPBoxes('.contact-otp-box');

  const msgEl = document.getElementById('set-contact-msg');
  msgEl.textContent = '';
  msgEl.className = 'settings-contact-msg';
}

async function sendContactOTP(resend) {
  if (!member) return;

  const hasMobile = !!member.mobile;
  const hasEmail  = !!member.email;

  // Figure out which field we're adding
  let field, value;
  if (!hasMobile) {
    field = 'mobile';
    value = document.getElementById('set-contact-mobile').value.trim().replace(/[\s\-]/g, '');
    if (!value) { showContactMsg('Please enter a mobile number', 'error'); return; }
    if (!/^09\d{9}$/.test(value)) {
      showContactMsg('Enter a valid PH mobile number (09XX XXX XXXX)', 'error');
      return;
    }
  } else if (!hasEmail) {
    field = 'email';
    value = document.getElementById('set-contact-email').value.trim();
    if (!value) { showContactMsg('Please enter an email address', 'error'); return; }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
      showContactMsg('Enter a valid email address', 'error');
      return;
    }
  } else {
    return;
  }

  _contactOTPField = field;
  _contactOTPValue = value;

  // Send OTP
  try {
    await fetch(`${API}/loyalty/otp/send`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ [field]: value })
    });
  } catch (e) {
    showContactMsg('Could not send verification code. Try again.', 'error');
    return;
  }

  // Show OTP input
  const otpSection = document.getElementById('set-contact-otp-section');
  const prompt     = document.getElementById('set-contact-otp-prompt');
  const sendBtn    = document.getElementById('set-contact-send-otp-btn');

  prompt.textContent = `Enter the 6-digit code we sent to ${value}`;
  otpSection.style.display = '';
  sendBtn.style.display = 'none';

  // Lock the input so they can't change it mid-verification
  document.getElementById(field === 'mobile' ? 'set-contact-mobile' : 'set-contact-email').disabled = true;

  if (!resend) {
    clearOTPBoxes('.contact-otp-box');
    setTimeout(() => document.querySelector('.contact-otp-box').focus(), 300);
  }

  showContactMsg(resend ? 'New code sent!' : '', resend ? 'success' : '');
}

let _verifyingContactOTP = false;

async function verifyContactOTP() {
  if (_verifyingContactOTP || !_contactOTPField || !_contactOTPValue) return;

  const boxes = document.querySelectorAll('.contact-otp-box');
  const otp   = Array.from(boxes).map(b => b.value).join('');
  if (otp.length < 6) return;

  _verifyingContactOTP = true;
  const btn = document.getElementById('set-contact-verify-btn');
  btn.disabled = true;
  btn.textContent = 'Verifying…';

  try {
    // Step 1: Verify OTP
    const vRes = await fetch(`${API}/loyalty/otp/verify`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ [_contactOTPField]: _contactOTPValue, otp })
    });
    const vData = await vRes.json();

    if (!vData.ok) {
      shakeOTPBoxes('.contact-otp-box');
      setTimeout(() => clearOTPBoxes('.contact-otp-box'), 500);
      showContactMsg('Incorrect code. Try again.', 'error');
      _verifyingContactOTP = false;
      btn.disabled = false;
      btn.textContent = 'Verify & add →';
      return;
    }

    // Step 2: OTP verified — now save the contact to the member record
    const pRes = await fetch(`${API}/loyalty/member/${encodeURIComponent(member.member_id)}/contact`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ [_contactOTPField]: _contactOTPValue })
    });
    const pData = await pRes.json();

    if (pData.ok && pData.member) {
      setMember(pData.member);
      populateContactFields();
      showContactMsg(_contactOTPField === 'mobile' ? 'Mobile number added!' : 'Email address added!', 'success');
    } else {
      showContactMsg(pData.error || 'Could not save. Try again.', 'error');
      // Unlock the input so they can fix it
      document.getElementById(_contactOTPField === 'mobile' ? 'set-contact-mobile' : 'set-contact-email').disabled = false;
    }
  } catch (e) {
    console.error('verifyContactOTP error:', e);
    showContactMsg('Network error. Try again.', 'error');
  } finally {
    _verifyingContactOTP = false;
    btn.disabled = false;
    btn.textContent = 'Verify & add →';
  }
}

function cancelContactOTP() {
  const otpSection = document.getElementById('set-contact-otp-section');
  const sendBtn    = document.getElementById('set-contact-send-otp-btn');
  otpSection.style.display = 'none';
  sendBtn.style.display = '';
  clearOTPBoxes('.contact-otp-box');

  // Unlock the field they were trying to add
  if (_contactOTPField) {
    const inputId = _contactOTPField === 'mobile' ? 'set-contact-mobile' : 'set-contact-email';
    document.getElementById(inputId).disabled = false;
  }
  _contactOTPField = null;
  _contactOTPValue = null;

  showContactMsg('', '');
}

function showContactMsg(text, type) {
  const el = document.getElementById('set-contact-msg');
  el.textContent = text;
  el.className = 'settings-contact-msg ' + (type || '');
  if (type === 'success') setTimeout(() => { el.textContent = ''; el.className = 'settings-contact-msg'; }, 3000);
}

/* ════ ENTER KEY: next field or submit ════ */

function setupEnterNav(containerId, fields, submitFn) {
  fields.forEach((selector, idx) => {
    const el = document.querySelector(`#${containerId} ${selector}`);
    if (!el) return;
    el.addEventListener('keydown', (e) => {
      if (e.key !== 'Enter') return;
      e.preventDefault();
      // Find next visible field
      for (let i = idx + 1; i < fields.length; i++) {
        const next = document.querySelector(`#${containerId} ${fields[i]}`);
        if (next && !next.closest('.hidden') && !next.disabled) {
          next.focus();
          return;
        }
      }
      // Last field — submit
      submitFn();
    });
  });
}

